import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import { awardXp } from '@/lib/xp'
import { shuffle } from '@/lib/vocab'
import { Header } from '@/components/Header'
import { XPToast, type XpToastData } from '@/components/XPToast'
import { ScoreScreen } from '@/components/ScoreScreen'

// Modus 3 — Satzreihenfolge laut CLAUDE.md §6.3.
//   - Quelle: sentences_medical (zufällig)
//   - DE-Satz oben angezeigt
//   - HU-Wörter als Tile-Buttons in zufälliger Reihenfolge
//   - User klickt sie in der gewünschten Reihenfolge → wandern in die Antwort-Zeile
//   - Prüfen-Button vergleicht mit korrektem Hungarian
//   - 1. Versuch korrekt: +20 XP, sonst +15 XP
//   - Score nach z.B. 5 Sätzen

const ROUND_LENGTH = 5

type Sentence = {
  id: number
  hungarian: string
  german: string
}

type Token = { id: number; word: string }

export default function Ordering() {
  const navigate = useNavigate()

  const [sentences, setSentences] = useState<Sentence[] | null>(null)
  const [round, setRound] = useState<Sentence[]>([])
  const [step, setStep] = useState(0)
  const [pool, setPool] = useState<Token[]>([])
  const [answer, setAnswer] = useState<Token[]>([])
  const [attempt, setAttempt] = useState(1)
  const [verdict, setVerdict] = useState<'pending' | 'correct' | 'wrong'>('pending')
  const [stats, setStats] = useState({ firstTry: 0, secondTry: 0, missed: 0, totalXp: 0 })
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)

  // Sätze laden
  useEffect(() => {
    let cancelled = false
    async function load() {
      const { data, error } = await supabase
        .from('sentences_medical')
        .select('id, hungarian, german')
      if (cancelled) return
      if (error) { setError(error.message); return }
      const all = (data ?? []) as Sentence[]
      if (all.length < ROUND_LENGTH) {
        setError(`Zu wenige Sätze in der DB (${all.length}).`)
        return
      }
      setSentences(all)
      const r = shuffle(all).slice(0, ROUND_LENGTH)
      setRound(r)
      setStep(0)
      loadStep(r[0])
    }
    void load()
    return () => { cancelled = true }
  }, [])

  function loadStep(sentence: Sentence) {
    const words = sentence.hungarian.replace(/[?.!]/g, ' ').split(/\s+/).filter(Boolean)
    const tokens: Token[] = words.map((w, i) => ({ id: i, word: w }))
    setPool(shuffle(tokens))
    setAnswer([])
    setAttempt(1)
    setVerdict('pending')
  }

  function pickToken(t: Token) {
    if (verdict !== 'pending') return
    setAnswer((a) => [...a, t])
    setPool((p) => p.filter((x) => x.id !== t.id))
  }

  function unpickToken(t: Token) {
    if (verdict !== 'pending') return
    setAnswer((a) => a.filter((x) => x.id !== t.id))
    setPool((p) => [...p, t])
  }

  async function handleCheck() {
    const sentence = round[step]
    const userAnswer = answer.map((t) => t.word).join(' ')
    const correct = sentence.hungarian.replace(/[?.!]/g, '').replace(/\s+/g, ' ').trim()
    const isCorrect = userAnswer.trim().toLowerCase() === correct.toLowerCase()

    if (isCorrect) {
      const baseXp = attempt === 1 ? 20 : 15
      const updated = { ...stats }
      if (attempt === 1) updated.firstTry += 1
      else updated.secondTry += 1
      updated.totalXp += baseXp
      setStats(updated)
      setVerdict('correct')

      void awardXp({
        baseAmount: baseXp,
        source: attempt === 1 ? 'ordering_first_try' : 'ordering_second_try',
        mode: 'medical'
      }).then((r) => r && setToast({ id: Date.now(), ...r }))

      // 1.2s warten, dann nächste Aufgabe
      setTimeout(() => advance(), 1200)
    } else {
      if (attempt === 1) {
        // Nochmal versuchen
        setAttempt(2)
        setVerdict('wrong')
        setTimeout(() => {
          // Antwort zurück in Pool, neuer Versuch
          setPool((p) => [...p, ...answer])
          setAnswer([])
          setVerdict('pending')
        }, 600)
      } else {
        // Zweiter Fehler → Lösung anzeigen + 0 XP
        setStats((s) => ({ ...s, missed: s.missed + 1 }))
        setVerdict('wrong')
        setTimeout(() => advance(), 1500)
      }
    }
  }

  function advance() {
    if (step + 1 >= round.length) {
      setDone(true)
      return
    }
    const nextStep = step + 1
    setStep(nextStep)
    loadStep(round[nextStep])
  }

  useEffect(() => {
    if (!toast) return
    const t = setTimeout(() => setToast(null), 1200)
    return () => clearTimeout(t)
  }, [toast])

  function restart() {
    if (!sentences) return
    const r = shuffle(sentences).slice(0, ROUND_LENGTH)
    setRound(r)
    setStep(0)
    setStats({ firstTry: 0, secondTry: 0, missed: 0, totalXp: 0 })
    setDone(false)
    loadStep(r[0])
  }

  if (error) {
    return <Wrapper><Status>⚠ {error}</Status><button onClick={() => navigate('/home')} style={btnGhost}>Zurück</button></Wrapper>
  }
  if (sentences === null) {
    return <Wrapper><Status>Sätze werden geladen…</Status></Wrapper>
  }
  if (done) {
    return (
      <ScoreScreen
        emoji="🌺"
        title="Runde geschafft!"
        subtitle={`${ROUND_LENGTH} Sätze fertig`}
        stats={[
          { label: '1. Versuch korrekt', value: stats.firstTry, highlight: true },
          { label: '2. Versuch korrekt', value: stats.secondTry },
          { label: 'Daneben', value: stats.missed }
        ]}
        totalXp={stats.totalXp}
        primaryAction={{ label: 'Nochmal', onClick: restart }}
        secondaryAction={{ label: 'Zurück zu Home', onClick: () => navigate('/home') }}
      />
    )
  }

  const sentence = round[step]
  const verdictColor =
    verdict === 'correct' ? 'var(--green)' :
    verdict === 'wrong' ? 'var(--red)' :
    'rgba(0,0,0,0.15)'

  return (
    <Wrapper>
      <div style={{ width: '100%', maxWidth: 480, fontSize: '0.85rem', opacity: 0.7, marginBottom: '0.5rem' }}>
        Satz {step + 1} / {round.length} · Versuch {attempt}
      </div>

      {/* DE-Satz */}
      <div
        style={{
          width: '100%',
          maxWidth: 480,
          background: 'var(--white)',
          border: '2px solid var(--green)',
          borderRadius: 12,
          padding: '1rem',
          textAlign: 'center',
          fontFamily: 'Georgia, serif',
          fontSize: '1.1rem',
          color: 'var(--green)',
          boxShadow: 'var(--shadow-card)'
        }}
      >
        {sentence.german}
      </div>

      {/* Antwort-Zeile */}
      <motion.div
        animate={verdict === 'wrong' ? { x: [0, -5, 5, -5, 5, 0] } : {}}
        transition={{ duration: 0.4 }}
        style={{
          width: '100%',
          maxWidth: 480,
          minHeight: 70,
          marginTop: '1rem',
          padding: '0.7rem',
          border: `2px dashed ${verdictColor}`,
          borderRadius: 12,
          background: 'rgba(255,255,255,0.5)',
          display: 'flex',
          flexWrap: 'wrap',
          gap: 6,
          alignItems: 'flex-start',
          alignContent: 'flex-start',
          transition: 'border-color 200ms'
        }}
      >
        {answer.length === 0 && (
          <span style={{ opacity: 0.4, fontSize: '0.85rem', alignSelf: 'center', margin: '0 auto' }}>
            Wörter unten antippen…
          </span>
        )}
        {answer.map((t) => (
          <button
            key={t.id}
            onClick={() => unpickToken(t)}
            style={tokenBtn(verdict === 'correct' ? 'var(--green)' : verdict === 'wrong' ? 'var(--red)' : 'var(--orange)')}
          >
            {t.word}
          </button>
        ))}
      </motion.div>

      {/* Pool */}
      <div
        style={{
          width: '100%',
          maxWidth: 480,
          marginTop: '0.8rem',
          padding: '0.5rem',
          display: 'flex',
          flexWrap: 'wrap',
          gap: 6,
          justifyContent: 'center'
        }}
      >
        {pool.map((t) => (
          <button key={t.id} onClick={() => pickToken(t)} style={tokenBtn('rgba(0,0,0,0.15)')}>
            {t.word}
          </button>
        ))}
      </div>

      <button
        onClick={handleCheck}
        disabled={answer.length === 0 || verdict !== 'pending'}
        style={{
          marginTop: '1.2rem',
          background: 'var(--red)',
          color: 'var(--cream)',
          border: 'none',
          padding: '0.7rem 1.6rem',
          borderRadius: 10,
          fontWeight: 700,
          fontSize: '0.95rem',
          fontFamily: 'inherit',
          cursor: answer.length === 0 || verdict !== 'pending' ? 'default' : 'pointer',
          opacity: answer.length === 0 || verdict !== 'pending' ? 0.5 : 1
        }}
      >
        Prüfen
      </button>

      {verdict === 'wrong' && attempt === 2 && (
        <div style={{ marginTop: '0.8rem', fontSize: '0.85rem', opacity: 0.7, fontStyle: 'italic', textAlign: 'center', maxWidth: 480 }}>
          Korrekt: <b>{sentence.hungarian}</b>
        </div>
      )}

      <button onClick={() => navigate('/home')} style={{ ...btnGhost, marginTop: '1.5rem' }}>
        Sitzung abbrechen
      </button>

      <XPToast toast={toast} />
    </Wrapper>
  )
}

function tokenBtn(borderColor: string): React.CSSProperties {
  return {
    background: 'var(--white)',
    border: `2px solid ${borderColor}`,
    padding: '0.5rem 0.85rem',
    borderRadius: 10,
    fontFamily: 'Georgia, serif',
    fontSize: '0.95rem',
    fontWeight: 700,
    cursor: 'pointer',
    color: 'inherit'
  }
}

function Wrapper({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}>
      <Header />
      <main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '1.5rem 1rem 3rem' }}>
        {children}
      </main>
    </div>
  )
}

function Status({ children }: { children: React.ReactNode }) {
  return <div style={{ opacity: 0.55, fontSize: '0.95rem', marginTop: '20vh' }}>{children}</div>
}

const btnGhost: React.CSSProperties = {
  background: 'none',
  border: '1.5px solid rgba(0,0,0,0.15)',
  padding: '0.45rem 0.9rem',
  borderRadius: 8,
  fontFamily: 'inherit',
  fontSize: '0.8rem',
  cursor: 'pointer',
  opacity: 0.65
}
